 21	import chart_color_blue_300 from '@patternfly/react-tokens/dist/esm/chart_color_blue_300';
 22	import chart_color_orange_300 from '@patternfly/react-tokens/dist/esm/chart_color_orange_300';
 23	import useDuration from '@virtualmachines/details/tabs/metrics/hooks/useDuration';
 24	
 25	import { tickLabels } from '../ChartLabels/styleOverrides';
 26	import ComponentReady from '../ComponentReady/ComponentReady';
 27	import useResponsiveCharts from '../hooks/useResponsiveCharts';
 28	import { getUtilizationQueries } from '../utils/queries';
 29	import {
 30	  findMaxYValue,
 31	  MILLISECONDS_MULTIPLIER,
 32	  queriesToLink,
 33	  tickFormat,
 34	  TICKS_COUNT,
 35	} from '../utils/utils';
 36	
 37	type CPUThresholdChartProps = {
 38	  pods: K8sResourceCommon[];
 39	  vmi: V1VirtualMachineInstance;
 40	};
 41	
 42	const CPUThresholdChart: FC<CPUThresholdChartProps> = ({ pods, vmi }) => {
 43	  const vmiPod = useMemo(() => getVMIPod(vmi, pods), [pods, vmi]);
 44	  const { currentTime, duration, timespan } = useDuration();
 45	  const { height, ref, width } = useResponsiveCharts();
 46	  const queries = useMemo(
 47	    () => getUtilizationQueries({ duration, launcherPodName: vmiPod?.metadata?.name, obj: vmi }),
 48	    [vmi, vmiPod, duration],
 49	  );
 50	
 51	  const [dataCPURequested] = usePrometheusPoll({
 52	    endpoint: PrometheusEndpoint?.QUERY_RANGE,
 53	    endTime: currentTime,
 54	    namespace: vmi?.metadata?.namespace,
 55	    query: queries.CPU_REQUESTED,
 56	    timespan,
 57	  });
 58	
 59	  const [dataCPUUsage] = usePrometheusPoll({
 60	    endpoint: PrometheusEndpoint?.QUERY_RANGE,
 61	    endTime: currentTime,
 62	    namespace: vmi?.metadata?.namespace,
 63	    query: queries?.CPU_USAGE,
 64	    timespan,
 65	  });
 66	
 67	  const cpuUsage = dataCPUUsage?.data?.result?.[0]?.values;
 68	  const cpuRequested = dataCPURequested?.data?.result?.[0]?.values;
 69	
 70	  const chartData = cpuUsage?.map(([x, y]) => {
 71	    return { name: 'CPU usage', x: new Date(x * MILLISECONDS_MULTIPLIER), y: Number(y) };
 72	  });
 73	
 74	  const thresholdData = cpuRequested?.map(([x, y]) => {
 75	    return { name: 'CPU requested', x: new Date(x * MILLISECONDS_MULTIPLIER), y: Number(y) };
 76	  });
 77	
 78	  const isReady = !isEmpty(chartData) && !isEmpty(thresholdData);
 79	  const linkToMetrics = queriesToLink(queries?.CPU_USAGE);
 80	  const yMax = findMaxYValue(thresholdData);
 81	  return (
 82	    <ComponentReady isReady={isReady} linkToMetrics={linkToMetrics}>
 83	      <div className="util-threshold-chart" ref={ref}>
 84	        <Link to={linkToMetrics}>
 85	          <Chart
 86	            containerComponent={
 87	              <ChartVoronoiContainer
 88	                labels={({ datum }) => {
 89	                  return `${datum?.name}: ${datum?.y?.toFixed(2)}'s`;
 90	                }}
 91	                constrainToVisibleArea
 92	              />
 93	            }
 94	            domain={{
 95	              x: [currentTime - timespan, currentTime],
 96	            }}
 97	            height={height}
 98	            padding={{ bottom: 35, left: 70, right: 35, top: 35 }}
 99	            scale={{ x: 'time', y: 'linear' }}
100	            width={width}
101	          >
102	            <ChartAxis
103	              style={{
104	                grid: {
105	                  stroke: chart_color_black_200.value,
106	                },
107	                tickLabels,
108	              }}
109	              dependentAxis
110	              tickFormat={(tick: number) => tick?.toFixed(2)}
111	              tickValues={[0, yMax]}
112	            />
113	            <ChartAxis
114	              style={{
115	                tickLabels: { padding: 2, ...tickLabels },
116	                ticks: { stroke: 'transparent' },
117	              }}
118	              axisComponent={<></>}
119	              tickCount={TICKS_COUNT}
120	              tickFormat={tickFormat(duration, currentTime)}
121	            />
122	            <ChartGroup>
123	              <ChartArea
124	                style={{
125	                  data: {
126	                    stroke: chart_color_blue_300.value,
127	                  },
128	                }}
129	                data={chartData}
130	              />
131	            </ChartGroup>
132	            <ChartThreshold
133	              style={{
134	                data: {
135	                  stroke: chart_color_orange_300.value,
136	                  strokeDasharray: 10,
137	                },
138	              }}
139	              data={thresholdData}
140	            />
141	          </Chart>
142	        </Link>
143	      </div>
144	    </ComponentReady>
145	  );
146	};
147	
148	export default CPUThresholdChart;

